import { PDFDocument, StandardFonts, rgb } from "pdf-lib";

// Template.pdf embedded as base64 — no file fetch needed
const TEMPLATE_B64 = "";

function b64ToArrayBuffer(b64) {
  const bin = atob(b64);
  const buf = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
  return buf.buffer;
}

function wrapText(text, font, fontSize, maxWidth) {
  const words = text.split(" ");
  const lines = [];
  let current = "";
  for (const word of words) {
    const candidate = current ? current + " " + word : word;
    if (font.widthOfTextAtSize(candidate, fontSize) > maxWidth && current) {
      lines.push(current);
      current = word;
    } else {
      current = candidate;
    }
  }
  if (current) lines.push(current);
  return lines;
}

function drawWrapped(page, text, { x, y, font, size, color, maxWidth, leading }) {
  let curY = y;
  for (const line of wrapText(text, font, size, maxWidth)) {
    page.drawText(line, { x, y: curY, size, font, color });
    curY -= leading;
  }
  return curY;
}

export async function exportProposal(company, industry, researchData, findIndustryUseCases) {
  const data = findIndustryUseCases(company, industry, researchData);

  // Load template from embedded base64 — no external file needed
  const templateBytes = b64ToArrayBuffer(TEMPLATE_B64);
  const pdfDoc = await PDFDocument.load(templateBytes);

  const regular = await pdfDoc.embedFont(StandardFonts.Helvetica);
  const bold    = await pdfDoc.embedFont(StandardFonts.HelveticaBold);

  const PAGE_W  = 1080;
  const PAGE_H  = 1440;
  const L       = 80;
  const R_MARGIN = 80;
  const MAX_W   = PAGE_W - L - R_MARGIN;

  const BLACK = rgb(0, 0, 0);
  const WHITE = rgb(1, 1, 1);
  const BLUE  = rgb(0.118, 0.451, 0.745);

  const page2 = pdfDoc.getPages()[1];

  // Erase placeholder heading + lorem ipsum block on page 2
  // Measured from actual template: heading top=140, lorem ends top=444
  // pdf-lib uses bottom-left origin: pdf_y = PAGE_H - pdfplumber_top
  const ERASE_BOTTOM = PAGE_H - 460;
  const ERASE_TOP    = PAGE_H - 120;
  page2.drawRectangle({
    x: L - 4,
    y: ERASE_BOTTOM,
    width: MAX_W + 8,
    height: ERASE_TOP - ERASE_BOTTOM,
    color: WHITE,
    borderWidth: 0,
  });

  // Heading
  const H_SIZE  = 40;
  const H_Y     = PAGE_H - 180;
  const prefix  = "How Condense Helps ";
  const prefixW = bold.widthOfTextAtSize(prefix, H_SIZE);
  page2.drawText(prefix,   { x: L,           y: H_Y, size: H_SIZE, font: bold, color: BLACK });
  page2.drawText(industry, { x: L + prefixW, y: H_Y, size: H_SIZE, font: bold, color: BLUE  });

  // Intro
  let curY = H_Y - 48;
  const BODY_SIZE = 20;
  const LEADING   = 28;

  if (data.intro) {
    curY = drawWrapped(page2, data.intro, {
      x: L, y: curY, font: regular, size: BODY_SIZE,
      color: BLACK, maxWidth: MAX_W, leading: LEADING,
    });
    curY -= 24;
  }

  // Use-case cards 2x2 grid
  const useCases = (data.use_cases || []).slice(0, 4);
  if (useCases.length > 0) {
    const GAP       = 20;
    const CARD_W    = (MAX_W - GAP) / 2;
    const CARD_H    = 160;
    const PAD_X     = 20;
    const PAD_Y     = 18;
    const T_SIZE    = 18;
    const B_SIZE    = 16;
    const B_LEADING = 22;

    for (let i = 0; i < useCases.length; i++) {
      const col   = i % 2;
      const row   = Math.floor(i / 2);
      const cardX = L + col * (CARD_W + GAP);
      const cardY = curY - row * (CARD_H + GAP) - CARD_H;

      page2.drawRectangle({
        x: cardX, y: cardY, width: CARD_W, height: CARD_H,
        color: rgb(0.97, 0.97, 0.97),
        borderColor: rgb(0.85, 0.85, 0.85),
        borderWidth: 1,
      });

      page2.drawText(useCases[i].title || "", {
        x: cardX + PAD_X,
        y: cardY + CARD_H - PAD_Y - T_SIZE,
        size: T_SIZE, font: bold, color: BLUE,
      });

      if (useCases[i].desc) {
        drawWrapped(page2, useCases[i].desc, {
          x: cardX + PAD_X,
          y: cardY + CARD_H - PAD_Y - T_SIZE - B_LEADING - 2,
          font: regular, size: B_SIZE, color: BLACK,
          maxWidth: CARD_W - PAD_X * 2,
          leading: B_LEADING,
        });
      }
    }

    const rows = Math.ceil(useCases.length / 2);
    curY -= rows * (CARD_H + GAP) + 20;
  }

  // Closing
  if (data.closing) {
    drawWrapped(page2, data.closing, {
      x: L, y: curY, font: regular, size: BODY_SIZE,
      color: BLACK, maxWidth: MAX_W, leading: LEADING,
    });
  }

  // Save all 3 pages and download
  const pdfBytes = await pdfDoc.save();
  const blob = new Blob([pdfBytes], { type: "application/pdf" });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement("a");
  a.href     = url;
  a.download = company + "_Condense_Proposal.pdf";
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}
